import{_ as o,o as e,c as r,ag as a}from"./chunks/framework.BMy1X8j3.js";const h=JSON.parse('{"title":"设计模式速查表","description":"","frontmatter":{},"headers":[],"relativePath":"claude_code_docs/appendix/patterns.md","filePath":"claude_code_docs/appendix/patterns.md"}'),s={name:"claude_code_docs/appendix/patterns.md"};function d(n,t,p,c,l,i){return e(),r("div",null,[...t[0]||(t[0]=[a(`<h1 id="设计模式速查表" tabindex="-1">设计模式速查表 <a class="header-anchor" href="#设计模式速查表" aria-label="Permalink to &quot;设计模式速查表&quot;">​</a></h1><blockquote><p>源码中反复出现的 13 种设计模式，按使用频率排列</p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Claude Code 源码中有一些反复出现的设计模式，它们不是教科书上的 GoF 模式，而是在 LLM agent 工程实践中自然演化出来的。本文汇总这些模式，便于快速检索和复用。</p><h2 id="模式总览" tabindex="-1">模式总览 <a class="header-anchor" href="#模式总览" aria-label="Permalink to &quot;模式总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>模式名称</th><th>核心源文件</th><th>一句话描述</th></tr></thead><tbody><tr><td>1</td><td>决策冻结</td><td><code>toolResultStorage.ts</code></td><td>一旦决定是否替换某个工具结果，永远不再改变</td></tr><tr><td>2</td><td>草稿纸模式</td><td><code>compact/prompt.ts</code></td><td>让模型先在 <code>&lt;analysis&gt;</code> 中思考，再在 <code>&lt;summary&gt;</code> 中输出，最后剥离 analysis</td></tr><tr><td>3</td><td>落盘+预览</td><td><code>toolResultStorage.ts</code></td><td>大结果写磁盘，上下文只放 2KB 预览 + 文件路径</td></tr><tr><td>4</td><td>逐字引用</td><td><code>compact/prompt.ts</code></td><td>要求模型逐字引用原文，防止多次压缩后意图漂移</td></tr><tr><td>5</td><td>熔断器</td><td><code>autoCompact.ts</code></td><td>连续失败 N 次后停止重试，防止无限循环</td></tr><tr><td>6</td><td>分层防御</td><td>多个文件</td><td>从源头到兜底的多层防线，成本递增、频率递减</td></tr><tr><td>7</td><td>静态/动态分区</td><td><code>prompts.ts</code></td><td>System prompt 分为可缓存的静态区和每会话变化的动态区</td></tr><tr><td>8</td><td>恢复消息注入</td><td><code>query.ts</code></td><td>模型输出被截断时，注入&quot;继续&quot;指令让模型无缝接续</td></tr><tr><td>9</td><td>空结果标记</td><td><code>FileReadTool/</code></td><td>文件未变时返回固定 stub 而非重新读取，节省上下文</td></tr><tr><td>10</td><td>memoize+手动清缓存</td><td><code>mcp/client.ts</code></td><td>用 memoize 缓存连接，但在认证失效时手动清除</td></tr><tr><td>11</td><td>外部监督者</td><td><code>hooks.ts</code></td><td>Stop hooks 检查模型输出，不满意则注入 error 强制继续</td></tr><tr><td>12</td><td>上下文继承</td><td><code>runAgent.ts</code></td><td>子 agent fork 父上下文的消息和缓存，共享 prompt cache 前缀</td></tr><tr><td>13</td><td>流式并行执行</td><td><code>StreamingToolExecutor</code></td><td>模型还在输出时就开始执行已完成的工具调用</td></tr></tbody></table><h2 id="模式详解" tabindex="-1">模式详解 <a class="header-anchor" href="#模式详解" aria-label="Permalink to &quot;模式详解&quot;">​</a></h2><h3 id="_1-决策冻结" tabindex="-1">1. 决策冻结 <a class="header-anchor" href="#_1-决策冻结" aria-label="Permalink to &quot;1. 决策冻结&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/utils/toolResultStorage.ts</code></p><p><strong>描述</strong>: 每个 tool_result 的命运（是否被替换为磁盘引用）在第一次被看到时冻结。之后每轮都用缓存的替换内容重新应用，保证字节级一致。</p><p><strong>何时用</strong>: 当下游系统（如 prompt cache）依赖内容稳定性时。一旦做出决定就不再改变，避免缓存失效。</p><p><strong>何时不用</strong>: 当内容确实需要动态更新时（如实时数据）。冻结会导致过时数据无法被替换。</p><h3 id="_2-草稿纸模式" tabindex="-1">2. 草稿纸模式 <a class="header-anchor" href="#_2-草稿纸模式" aria-label="Permalink to &quot;2. 草稿纸模式&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/services/compact/prompt.ts</code></p><p><strong>描述</strong>: 压缩时要求模型先在 <code>&lt;analysis&gt;</code> 标签中分析，再在 <code>&lt;summary&gt;</code> 标签中输出摘要。<code>&lt;analysis&gt;</code> 部分被 <code>formatCompactSummary()</code> 剥离，不进入最终上下文。</p><p><strong>何时用</strong>: 需要模型深度思考但不想让思考过程占用上下文时。类似 chain-of-thought 但不保留中间步骤。</p><p><strong>何时不用</strong>: 当思考过程本身就是有价值的输出时（如代码审查的推理过程）。</p><h3 id="_3-落盘-预览" tabindex="-1">3. 落盘+预览 <a class="header-anchor" href="#_3-落盘-预览" aria-label="Permalink to &quot;3. 落盘+预览&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/utils/toolResultStorage.ts</code></p><p><strong>描述</strong>: 工具结果超过 50K 字符时，完整内容写入磁盘文件，上下文中只放 2KB 预览和文件路径。模型可以用 Read 工具按需回查。</p><p><strong>何时用</strong>: 工具可能产生大量输出（搜索结果、日志、大文件）。保证上下文不被单个结果撑爆。</p><p><strong>何时不用</strong>: 当结果必须完整呈现给模型时（如需要全文分析的场景）。</p><h3 id="_4-逐字引用" tabindex="-1">4. 逐字引用 <a class="header-anchor" href="#_4-逐字引用" aria-label="Permalink to &quot;4. 逐字引用&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/services/compact/prompt.ts</code></p><p><strong>描述</strong>: 压缩摘要中要求模型逐字引用用户的原始任务描述，而不是用自己的话重新表述。防止多次压缩后任务描述逐渐偏离原意（&quot;传话游戏&quot;效应）。</p><p><strong>何时用</strong>: 任何需要跨多轮保持信息准确性的场景。特别是会被反复摘要/压缩的关键信息。</p><p><strong>何时不用</strong>: 当原文本身就很长，逐字引用会占用过多空间时。</p><h3 id="_5-熔断器" tabindex="-1">5. 熔断器 <a class="header-anchor" href="#_5-熔断器" aria-label="Permalink to &quot;5. 熔断器&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/services/compact/autoCompact.ts</code></p><p><strong>描述</strong>: 连续自动压缩失败 3 次后停止重试。源码注释记录了曾有 1,279 个会话出现 50+ 次连续失败，每天浪费约 25 万次 API 调用。</p><p><strong>何时用</strong>: 任何可能失败的自动重试逻辑。特别是失败后重试可能继续失败的场景（如上下文已经无法压缩）。</p><p><strong>何时不用</strong>: 当每次重试都有合理的成功预期时（如网络抖动导致的临时失败）。</p><h3 id="_6-分层防御" tabindex="-1">6. 分层防御 <a class="header-anchor" href="#_6-分层防御" aria-label="Permalink to &quot;6. 分层防御&quot;">​</a></h3><p><strong>源文件</strong>: 五层防爆体系涉及多个文件</p><p><strong>描述</strong>: 从 L1（源头截断）到 L5（兜底截断），每层解决不同粒度的问题。便宜的操作先做，昂贵的操作只在必要时触发。</p><p><strong>何时用</strong>: 需要防御多种规模问题的系统。核心是&quot;大多数情况用便宜的方案解决，只有极端情况才用昂贵方案&quot;。</p><p><strong>何时不用</strong>: 问题规模单一、不需要多级处理的简单场景。</p><h3 id="_7-静态-动态分区" tabindex="-1">7. 静态/动态分区 <a class="header-anchor" href="#_7-静态-动态分区" aria-label="Permalink to &quot;7. 静态/动态分区&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/constants/prompts.ts</code></p><p><strong>描述</strong>: System prompt 在 <code>SYSTEM_PROMPT_DYNAMIC_BOUNDARY</code> 处分为两部分。静态区（身份、工具、规范）跨会话可缓存，动态区（语言、MCP 指令、环境信息）每会话不同。</p><p><strong>何时用</strong>: 使用 prompt cache 的任何应用。把不变的内容放前面，变化的内容放后面。</p><p><strong>何时不用</strong>: 不使用 prompt cache 或 prompt 很短的场景。</p><h3 id="_8-恢复消息注入" tabindex="-1">8. 恢复消息注入 <a class="header-anchor" href="#_8-恢复消息注入" aria-label="Permalink to &quot;8. 恢复消息注入&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/query.ts</code></p><p><strong>描述</strong>: 模型输出被 <code>max_output_tokens</code> 截断时，注入一条用户消息：&quot;Resume directly — no apology, no recap. Break remaining work into smaller pieces.&quot; 让模型无缝接续。</p><p><strong>何时用</strong>: 模型输出可能被截断的场景。注入的消息要明确告诉模型&quot;不要道歉、不要重复、直接继续&quot;。</p><p><strong>何时不用</strong>: 输出不会被截断的场景，或截断后不需要继续的场景。</p><h3 id="_9-空结果标记" tabindex="-1">9. 空结果标记 <a class="header-anchor" href="#_9-空结果标记" aria-label="Permalink to &quot;9. 空结果标记&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/tools/FileReadTool/</code></p><p><strong>描述</strong>: 文件内容未变时返回固定的 stub 字符串（&quot;File unchanged since last read...&quot;），而不是重新读取完整内容。通过 <code>readFileState</code> 的内容哈希追踪。</p><p><strong>何时用</strong>: 同一资源可能被多次请求但内容不变的场景。用固定标记替代重复内容。</p><p><strong>何时不用</strong>: 资源内容频繁变化，或每次都需要最新内容的场景。</p><h3 id="_10-memoize-手动清缓存" tabindex="-1">10. memoize+手动清缓存 <a class="header-anchor" href="#_10-memoize-手动清缓存" aria-label="Permalink to &quot;10. memoize+手动清缓存&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/services/mcp/client.ts</code></p><p><strong>描述</strong>: <code>connectToServer</code> 用 lodash <code>memoize</code> 缓存连接结果，相同配置不重复连接。但在认证失效（401）时手动清除缓存条目，触发重新连接。</p><p><strong>何时用</strong>: 资源创建昂贵但偶尔需要刷新的场景。memoize 提供默认缓存，手动清除处理异常。</p><p><strong>何时不用</strong>: 资源创建便宜或需要频繁刷新的场景。</p><h3 id="_11-外部监督者" tabindex="-1">11. 外部监督者 <a class="header-anchor" href="#_11-外部监督者" aria-label="Permalink to &quot;11. 外部监督者&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/utils/hooks.ts</code></p><p><strong>描述</strong>: Stop hooks 在模型宣布&quot;完成&quot;时执行外部检查。如果检查不通过，注入 blocking error 消息，强制模型继续工作。模型自己不知道有这个监督者。</p><p><strong>何时用</strong>: 需要验证模型输出质量的场景。特别是模型可能过早宣布&quot;完成&quot;的长任务。</p><p><strong>何时不用</strong>: 简单的问答场景，或模型输出不需要验证的场景。</p><h3 id="_12-上下文继承" tabindex="-1">12. 上下文继承 <a class="header-anchor" href="#_12-上下文继承" aria-label="Permalink to &quot;12. 上下文继承&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/tools/AgentTool/runAgent.ts</code></p><p><strong>描述</strong>: 子 agent 可以 fork 父 agent 的消息历史和 <code>readFileState</code> 缓存，共享 prompt cache 前缀。但有独立的 agentId 和 transcript。</p><p><strong>何时用</strong>: 子任务需要父任务的上下文但不应该污染父上下文的场景。fork 而非共享。</p><p><strong>何时不用</strong>: 子任务完全独立，不需要父上下文的场景（如并行的独立搜索）。</p><h3 id="_13-流式并行执行" tabindex="-1">13. 流式并行执行 <a class="header-anchor" href="#_13-流式并行执行" aria-label="Permalink to &quot;13. 流式并行执行&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/StreamingToolExecutor.ts</code></p><p><strong>描述</strong>: 不等模型输出完毕，每个 tool_use block 完成后立即开始执行。多个工具调用可以并行执行。</p><p><strong>何时用</strong>: 模型可能在一次输出中调用多个独立工具的场景。显著减少等待时间。</p><p><strong>何时不用</strong>: 工具调用之间有依赖关系，必须串行执行的场景。</p><h2 id="补充模式" tabindex="-1">补充模式 <a class="header-anchor" href="#补充模式" aria-label="Permalink to &quot;补充模式&quot;">​</a></h2><p>以下模式在源码中同样反复出现，与上述 13 种模式互补。</p><h3 id="_14-统一接口" tabindex="-1">14. 统一接口 <a class="header-anchor" href="#_14-统一接口" aria-label="Permalink to &quot;14. 统一接口&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/Tool.ts</code></p><p><strong>描述</strong>: 40+ 个工具都遵循同一个 <code>Tool&lt;Input, Output, Progress&gt;</code> 接口，通过 <code>buildTool()</code> 工厂函数构建。调用者不需要知道具体是哪个工具——所有工具都通过 <code>tool.call(input)</code> 执行。</p><p><strong>何时用</strong>: 需要插件/工具系统的任何框架。统一接口让新工具的添加不需要修改调用方代码。</p><p><strong>何时不用</strong>: 工具之间差异极大，强制统一接口会导致过度抽象。</p><h3 id="_15-策略模式" tabindex="-1">15. 策略模式 <a class="header-anchor" href="#_15-策略模式" aria-label="Permalink to &quot;15. 策略模式&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/utils/permissions/PermissionMode.ts</code></p><p><strong>描述</strong>: 不同的权限模式（default/acceptEdits/bypassPermissions/plan）是不同的&quot;策略&quot;。运行时根据用户选择切换权限检查算法，而不是用 if/else 硬编码。</p><p><strong>何时用</strong>: 同一个操作有多种处理方式，需要在运行时切换。</p><p><strong>何时不用</strong>: 只有一种处理方式，策略模式会增加不必要的抽象层。</p><h3 id="_16-渐进增强" tabindex="-1">16. 渐进增强 <a class="header-anchor" href="#_16-渐进增强" aria-label="Permalink to &quot;16. 渐进增强&quot;">​</a></h3><p><strong>源文件</strong>: <code>src/main.tsx</code></p><p><strong>描述</strong>: 基础工具（Bash、FileRead、FileEdit）总是可用，高级功能（Voice、Browser、LSP）通过 feature flag 按需启用。未启用的功能甚至不会被加载到内存（<code>require()</code> 而非 <code>import</code>）。</p><p><strong>何时用</strong>: 功能集合庞大但大部分用户只需要子集的场景。保证基础功能稳定，高级功能不影响启动速度。</p><p><strong>何时不用</strong>: 所有功能都是核心功能，不存在可选子集。</p><h3 id="模式的组合" tabindex="-1">模式的组合 <a class="header-anchor" href="#模式的组合" aria-label="Permalink to &quot;模式的组合&quot;">​</a></h3><p>实际系统中模式很少单独出现。以工具执行流程为例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>统一接口 → 所有工具用同一个 call() 方法</span></span>
<span class="line"><span>  + 策略模式 → 不同的权限检查策略</span></span>
<span class="line"><span>  + 事件驱动 → Hook 在执行前后触发</span></span>
<span class="line"><span>  + 分层防御 → 多层安全检查</span></span>
<span class="line"><span>  + 缓存策略 → 工具 schema 缓存</span></span>
<span class="line"><span>  = 一个既灵活又安全又高效的工具执行系统</span></span></code></pre></div>`,92)])])}const u=o(s,[["render",d]]);export{h as __pageData,u as default};
